using System;
using System.Reflection;

// Get assembly references
var agentsAssembly = typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly;
var extensionsAssembly = typeof(Microsoft.Extensions.AI.ChatOptions).Assembly;

Console.WriteLine("=== Microsoft.Agents.AI ===");
PrintTypeInfo(agentsAssembly, "Microsoft.Agents.AI.ChatClientAgent");
PrintTypeInfo(agentsAssembly, "Microsoft.Agents.AI.ChatClientAgentOptions");
PrintTypeInfo(agentsAssembly, "Microsoft.Agents.AI.ChatClientAgentRunOptions");
PrintTypeInfo(agentsAssembly, "Microsoft.Agents.AI.AgentRunOptions");

Console.WriteLine("\n=== Microsoft.Extensions.AI ===");
PrintTypeInfo(extensionsAssembly, "Microsoft.Extensions.AI.IChatClient");
PrintTypeInfo(extensionsAssembly, "Microsoft.Extensions.AI.ChatOptions");
PrintTypeInfo(extensionsAssembly, "Microsoft.Extensions.AI.AITool");
PrintTypeInfo(extensionsAssembly, "Microsoft.Extensions.AI.AIFunction");

void PrintTypeInfo(Assembly assembly, string typeName)
{
    var type = assembly.GetType(typeName);
    if (type == null)
    {
        Console.WriteLine($"\n{typeName} - NOT FOUND");
        return;
    }

    Console.WriteLine($"\n{typeName}");
    Console.WriteLine($"  BaseType: {type.BaseType?.Name}");

    var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    if (constructors.Length > 0)
    {
        Console.WriteLine("  Constructors:");
        foreach (var ctor in constructors)
        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    public {type.Name}({parms})");
        }
    }

    var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    if (properties.Length > 0)
    {
        Console.WriteLine("  Properties:");
        foreach (var prop in properties.OrderBy(p => p.Name))
        {
            Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} {{ get; {(prop.CanWrite ? "set;" : "")} }}");
        }
    }

    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName).OrderBy(m => m.Name);
    if (methods.Any())
    {
        Console.WriteLine("  Methods:");
        foreach (var method in methods.Take(20))
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name}"));
            Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({parms})");
        }
        if (methods.Count() > 20)
            Console.WriteLine($"    ... and {methods.Count() - 20} more");
    }
}
EOF

