var agentsAssembly = typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly;
var extensionsAssembly = typeof(Microsoft.Extensions.AI.ChatOptions).Assembly;

Console.WriteLine("=== AIAgent Base Class ===");
PrintTypeInfo(agentsAssembly, "Microsoft.Agents.AI.AIAgent");

Console.WriteLine("\n=== AgentRunOptions ===");
PrintTypeInfo(agentsAssembly, "Microsoft.Agents.AI.AgentRunOptions");

Console.WriteLine("\n=== AIFunctionFactory ===");
PrintTypeInfo(extensionsAssembly, "Microsoft.Extensions.AI.AIFunctionFactory");

Console.WriteLine("\n=== Methods on ChatClientAgent ===");
var chatClientAgent = agentsAssembly.GetType("Microsoft.Agents.AI.ChatClientAgent");
PrintMethods(chatClientAgent);

void PrintTypeInfo(Assembly assembly, string typeName)
{
    var type = assembly.GetType(typeName);
    if (type == null)
    {
        Console.WriteLine($"{typeName} - NOT FOUND");
        return;
    }

    Console.WriteLine($"{typeName}");
    if (type.BaseType != null && type.BaseType.Name != "Object")
        Console.WriteLine($"  Extends: {type.BaseType.Name}");

    var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static);
    if (constructors.Length > 0)
    {
        Console.WriteLine("  Constructors:");
        foreach (var ctor in constructors.Take(5))
        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    public {type.Name}({parms})");
        }
    }

    var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    if (properties.Length > 0)
    {
        Console.WriteLine("  Properties (DeclaredOnly):");
        foreach (var prop in properties.OrderBy(p => p.Name).Take(20))
        {
            Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} {{ get; {(prop.CanWrite ? "set;" : "")} }}");
        }
    }
}

void PrintMethods(Type type)
{
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName && !m.Name.StartsWith("get_") && !m.Name.StartsWith("set_"))
        .OrderBy(m => m.Name);

    Console.WriteLine($"  Public Methods on {type.Name}:");
    foreach (var method in methods.Take(30))
    {
        var parms = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name));
        var returnType = method.ReturnType.Name;
        if (method.ReturnType.IsGenericType)
            returnType = method.ReturnType.Name.Split('`')[0] + "<...>";
        Console.WriteLine($"    {returnType} {method.Name}({parms})");
    }
}
EOF
