using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent;

var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

services.AddChatClient(b => b
    .UseLogging()
    .Use(new OpenAIClient(apiKey).GetChatClient(modelId)));

var sp = services.BuildServiceProvider();

var notebook = new Notebook();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        WebSearchTool.SearchAsync,
        new AIFunctionFactoryOptions { Name = "web_search", Description = "Search the web for information on a query. Returns a list of result snippets." }),

    AIFunctionFactory.Create(
        notebook.AddNote,
        new AIFunctionFactoryOptions { Name = "take_note", Description = "Save an important finding as a note. Use this to record key facts discovered during research." }),

    AIFunctionFactory.Create(
        notebook.GetNotes,
        new AIFunctionFactoryOptions { Name = "get_notes", Description = "Retrieve all notes taken so far." }),
};

var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An AI agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = tools,
    },
};

var agent = new ChatClientAgent(
    sp.GetRequiredService<IChatClient>(),
    agentOptions,
    sp.GetRequiredService<ILoggerFactory>(),
    sp);

var session = await agent.CreateSessionAsync(CancellationToken.None);

var topic = args.Length > 0
    ? string.Join(' ', args)
    : "recent advances in quantum computing 2025";

Console.WriteLine($"🔍 Researching: {topic}\n");

var prompt = $"""
    You are a research assistant. Your task is to research the following topic thoroughly.

    Topic: {topic}

    Instructions:
    1. Use the web_search tool to search for information about this topic. Perform 2-3 searches with different queries to get broad coverage.
    2. After each search, use the take_note tool to record the most important findings.
    3. After completing your research, use get_notes to review all your findings.
    4. Finally, provide a well-structured summary with these sections:
       - **Overview**: A brief introduction to the topic
       - **Key Findings**: The most important discoveries from your research
       - **Details**: Deeper analysis of the findings
       - **Conclusion**: Your synthesis of the research

    Be thorough and cite specific facts from your search results.
    """;

var response = await agent.RunAsync(
    prompt,
    session,
    new ChatClientAgentRunOptions(),
    CancellationToken.None);

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("           RESEARCH SUMMARY            ");
Console.WriteLine("═══════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n--- Token usage: input={usage.InputTokenCount}, output={usage.OutputTokenCount} ---");
}

