using System.Net;
using System.Text.Json;
using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// Provides web search capability by querying a public search API.
/// Falls back to a simulated response when no search API key is configured.
/// </summary>
public static class WebSearchTool
{
    private static readonly HttpClient HttpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);

        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            return await SearchWithBraveAsync(query)
                ?? await SearchWithGoogleAsync(query)
                ?? GetFallbackResponse(query);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Search error: {ex.Message}");
            return GetFallbackResponse(query);
        }
    }

    private static async Task<string?> SearchWithBraveAsync(string query)
    {
        var apiKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY");
        if (string.IsNullOrEmpty(apiKey))
            return null;

        var url = $"https://api.search.brave.com/res/v1/web/search?q={WebUtility.UrlEncode(query)}&count=5";
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("X-Subscription-Token", apiKey);
        request.Headers.Add("Accept", "application/json");

        using var response = await HttpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        return ParseBraveResults(json);
    }

    private static string ParseBraveResults(string json)
    {
        using var doc = JsonDocument.Parse(json);
        var results = new List<string>();

        if (doc.RootElement.TryGetProperty("web", out var web) &&
            web.TryGetProperty("results", out var items))
        {
            foreach (var item in items.EnumerateArray().Take(5))
            {
                var title = item.GetProperty("title").GetString();
                var description = item.TryGetProperty("description", out var desc)
                    ? desc.GetString() : "";
                var itemUrl = item.GetProperty("url").GetString();
                results.Add($"- **{title}** ({itemUrl})\n  {description}");
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found.";
    }

    private static async Task<string?> SearchWithGoogleAsync(string query)
    {
        var apiKey = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_API_KEY");
        var cx = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_CX");
        if (string.IsNullOrEmpty(apiKey) || string.IsNullOrEmpty(cx))
            return null;

        var url = $"https://www.googleapis.com/customsearch/v1?key={apiKey}&cx={cx}&q={WebUtility.UrlEncode(query)}&num=5";
        using var response = await HttpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        return ParseGoogleResults(json);
    }

    private static string ParseGoogleResults(string json)
    {
        using var doc = JsonDocument.Parse(json);
        var results = new List<string>();

        if (doc.RootElement.TryGetProperty("items", out var items))
        {
            foreach (var item in items.EnumerateArray().Take(5))
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.TryGetProperty("snippet", out var s) ? s.GetString() : "";
                var link = item.GetProperty("link").GetString();
                results.Add($"- **{title}** ({link})\n  {snippet}");
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found.";
    }

    private static string GetFallbackResponse(string query)
    {
        Console.WriteLine("  ℹ️  Using simulated results (set BRAVE_SEARCH_API_KEY or GOOGLE_SEARCH_API_KEY for live search)");
        return $"""
            Simulated search results for "{query}":

            - **Wikipedia: {query}** (https://en.wikipedia.org/wiki/{WebUtility.UrlEncode(query)})
              A comprehensive overview of {query}, covering history, key concepts, and recent developments.

            - **Nature: Recent Research on {query}** (https://nature.com/articles/example)
              Peer-reviewed research highlighting breakthroughs and current challenges in the field of {query}.

            - **MIT Technology Review: {query}** (https://technologyreview.com/topic/example)
              Analysis of how {query} is evolving and its potential impact on industry and society.

            - **arXiv: Latest Papers on {query}** (https://arxiv.org/search/?query={WebUtility.UrlEncode(query)})
              Recent preprints and academic papers discussing advances in {query}.

            - **Reuters: {query} Developments** (https://reuters.com/technology/example)
              News coverage of the latest developments and commercial applications related to {query}.

            Note: These are simulated results. For real web search, configure a search API key.
            """;
    }
}

using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// A simple note-taking tool that the agent uses to record key findings during research.
/// </summary>
public sealed class Notebook
{
    private readonly List<string> _notes = [];

    public string AddNote(
        [Description("The note text to save — a key finding or important fact")] string note)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(note);

        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var formatted = _notes.Select((n, i) => $"{i + 1}. {n}");
        return $"All notes ({_notes.Count} total):\n{string.Join("\n", formatted)}";
    }
}

